export interface NavItem {
  label: string
  icon: string
  to?: string
  permission?: string
  meta?: Record<string, any>
}

export interface NavGroup {
  label: string
  icon: string
  children: NavItem[]
}

export type NavEntry = NavItem | NavGroup

export function isNavGroup(entry: NavEntry): entry is NavGroup {
  return 'children' in entry
}

// Groups are defined by which paths they collect, in display order.
// The group appears at the position of its first matching child in the route list.
const GROUP_DEFS: { label: string; icon: string; paths: string[] }[] = [
  { label: '项目管理', icon: 'i-heroicons-folder', paths: ['/app/projects', '/app/repos'] },
  { label: '用户管理', icon: 'i-heroicons-users', paths: ['/app/users', '/app/permissions'] },
]

export const useNavigation = () => {
  const { can, user } = useAuth()
  const { routes, loaded } = usePagePerms()

  const navItems = computed<NavItem[]>(() => {
    if (!loaded.value) return []
    return routes.value
      .filter(r => r.show_in_nav && r.is_active)
      .map(r => ({
        label: r.label,
        icon: r.icon,
        to: r.path,
        permission: r.permission ?? undefined,
        meta: r.meta,
      }))
  })

  const filteredNavItems = computed(() => {
    if (!user.value) return []
    return navItems.value.filter(item => {
      if (item.meta?.superuserOnly && !user.value?.is_superuser) return false
      if (item.permission && !can(item.permission)) return false
      return true
    })
  })

  // Grouped nav: items belonging to a GROUP_DEF are collapsed under a parent entry.
  // Order follows the original route list (group inserted at position of first matching child).
  const groupedNavItems = computed<NavEntry[]>(() => {
    const items = filteredNavItems.value
    const pathToGroupDef = new Map<string, typeof GROUP_DEFS[0]>()
    for (const def of GROUP_DEFS) {
      for (const path of def.paths) pathToGroupDef.set(path, def)
    }

    const result: NavEntry[] = []
    const emittedGroupLabels = new Set<string>()

    for (const item of items) {
      if (!item.to) { result.push(item); continue }
      const def = pathToGroupDef.get(item.to)
      if (!def) { result.push(item); continue }
      if (emittedGroupLabels.has(def.label)) continue
      emittedGroupLabels.add(def.label)
      const children = def.paths
        .map(p => items.find(i => i.to === p))
        .filter(Boolean) as NavItem[]
      result.push({ label: def.label, icon: def.icon, children })
    }

    return result
  })

  const route = useRoute()
  const currentPath = computed(() => route.path)

  // 不在 navItems 中的独立页面
  const standalonePages: Record<string, string> = {
    '/app/profile': '个人资料',
    '/app/about': '关于系统',
    '/app/notifications': '通知中心',
  }

  const breadcrumbs = computed(() => {
    const path = route.path
    const crumbs: { label: string; to?: string }[] = [{ label: '首页', to: '/app/issues' }]

    // 独立页面直接返回页面标题，不显示"首页"面包屑
    const standaloneName = standalonePages[path]
    if (standaloneName) {
      return [{ label: standaloneName }]
    }

    for (const item of navItems.value) {
      if (item.to === path) {
        crumbs.push({ label: item.label })
        return crumbs
      }
    }

    for (const item of navItems.value) {
      if (item.to && path.startsWith(item.to + '/')) {
        crumbs.push({ label: item.label, to: item.to })
        crumbs.push({ label: '详情' })
        return crumbs
      }
    }

    return crumbs
  })

  return { navItems, filteredNavItems, groupedNavItems, currentPath, breadcrumbs }
}

from rest_framework import status
from rest_framework.permissions import AllowAny
from rest_framework.response import Response
from rest_framework.views import APIView
from rest_framework.pagination import PageNumberPagination
from apps.issues.models import Issue, Activity
from .authentication import APIKeyAuthentication
from .serializers import ExternalIssueCreateSerializer, ExternalIssueResponseSerializer


class ExternalPagination(PageNumberPagination):
    page_size = 20
    page_size_query_param = "page_size"
    max_page_size = 100


class ExternalIssueListCreateView(APIView):
    authentication_classes = [APIKeyAuthentication]
    permission_classes = [AllowAny]

    def post(self, request):
        if not hasattr(request, "api_key") or request.api_key is None:
            return Response(
                {"detail": "认证失败"}, status=status.HTTP_401_UNAUTHORIZED
            )

        serializer = ExternalIssueCreateSerializer(data=request.data)
        serializer.is_valid(raise_exception=True)
        data = serializer.validated_data

        # Duplicate check
        feedback_id = data.get("source_feedback_id", "")
        if feedback_id:
            existing = Issue.objects.filter(
                source="agent_platform",
                source_meta__feedback_id=feedback_id,
                project=request.api_key.project,
            ).first()
            if existing:
                return Response(
                    {"detail": "反馈已存在", "existing_issue_id": existing.pk},
                    status=status.HTTP_409_CONFLICT,
                )

        # Build source_meta
        source_meta = {}
        if feedback_id:
            source_meta["feedback_id"] = feedback_id
        if data.get("reporter"):
            source_meta["reporter"] = data["reporter"]
        if data.get("context"):
            source_meta["context"] = data["context"]
        if data.get("attachments"):
            source_meta["attachments"] = data["attachments"]

        issue = Issue.objects.create(
            title=data["title"],
            description=data.get("description", ""),
            priority=data.get("priority", "P2"),
            labels=data.get("_labels", []),
            status="待处理",
            source="agent_platform",
            source_meta=source_meta or None,
            project=request.api_key.project,
            assignee=request.api_key.default_assignee,
            reporter=request.api_key.default_assignee,
        )

        Activity.objects.create(
            user=request.api_key.default_assignee,
            issue=issue,
            action="created",
            detail="通过外部 API 创建",
        )

        response_serializer = ExternalIssueResponseSerializer(issue)
        return Response(response_serializer.data, status=status.HTTP_201_CREATED)

    def get(self, request):
        if not hasattr(request, "api_key") or request.api_key is None:
            return Response(
                {"detail": "认证失败"}, status=status.HTTP_401_UNAUTHORIZED
            )

        qs = Issue.objects.select_related("assignee").filter(
            source="agent_platform",
            project=request.api_key.project,
        )

        # Filters
        feedback_id = request.query_params.get("feedback_id")
        if feedback_id:
            qs = qs.filter(source_meta__feedback_id=feedback_id)
        issue_status = request.query_params.get("status")
        if issue_status:
            qs = qs.filter(status=issue_status)
        priority = request.query_params.get("priority")
        if priority:
            qs = qs.filter(priority=priority)

        paginator = ExternalPagination()
        page = paginator.paginate_queryset(qs, request)
        serializer = ExternalIssueResponseSerializer(page, many=True)
        return paginator.get_paginated_response(serializer.data)


class ExternalIssueDetailView(APIView):
    authentication_classes = [APIKeyAuthentication]
    permission_classes = [AllowAny]

    def get(self, request, pk):
        if not hasattr(request, "api_key") or request.api_key is None:
            return Response(
                {"detail": "认证失败"}, status=status.HTTP_401_UNAUTHORIZED
            )

        issue = Issue.objects.select_related("assignee").filter(
            pk=pk,
            source="agent_platform",
            project=request.api_key.project,
        ).first()

        if not issue:
            return Response(
                {"detail": "问题不存在"}, status=status.HTTP_404_NOT_FOUND
            )

        serializer = ExternalIssueResponseSerializer(issue)
        return Response(serializer.data)

import os
import platform
import subprocess

import django
import rest_framework
from rest_framework.permissions import IsAdminUser
from rest_framework.response import Response
from rest_framework.views import APIView

from config.settings import BASE_DIR


def _read_version_file():
    """读取 CI 生成的 VERSION 文件"""
    version_file = BASE_DIR / "VERSION"
    if version_file.exists():
        return version_file.read_text().strip()
    return None


def _get_git_hash():
    """获取当前 git commit hash"""
    try:
        result = subprocess.run(
            ["git", "rev-parse", "--short", "HEAD"],
            capture_output=True,
            text=True,
            timeout=5,
            cwd=BASE_DIR,
        )
        if result.returncode == 0:
            return result.stdout.strip()
    except (FileNotFoundError, subprocess.TimeoutExpired):
        pass
    return None


def _get_pyproject_version():
    """从 pyproject.toml 读取版本号"""
    pyproject = BASE_DIR / "pyproject.toml"
    if pyproject.exists():
        for line in pyproject.read_text().splitlines():
            if line.strip().startswith("version"):
                return line.split("=")[1].strip().strip('"').strip("'")
    return None


class AboutView(APIView):
    permission_classes = [IsAdminUser]

    def get(self, request):
        build_version = _read_version_file()
        git_hash = None
        build_date = None

        if build_version and "-" in build_version:
            # 格式: YYYY-MM-DD-HH:MM:SS-SHORT_SHA
            parts = build_version.rsplit("-", 1)
            if len(parts) == 2:
                build_date = parts[0]
                git_hash = parts[1]

        if not git_hash:
            git_hash = _get_git_hash()

        return Response(
            {
                "backend": {
                    "version": _get_pyproject_version() or "0.1.0",
                    "git_hash": git_hash,
                    "build_date": build_date,
                    "python_version": platform.python_version(),
                    "django_version": django.get_version(),
                    "drf_version": rest_framework.VERSION,
                },
                "environment": {
                    "debug": os.environ.get("DJANGO_DEBUG", "True").lower()
                    in ("true", "1"),
                    "database": os.environ.get("DB_HOST", "127.0.0.1")
                    + ":"
                    + os.environ.get("DB_PORT", "25432"),
                },
            }
        )

